//go:build vectors

package ingest

import (
	"context"
	"os"
	"path/filepath"
	"testing"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
	"github.com/a<HOME>/agentic-rag-mcp/internal/embedder"
)

func TestAtomicRebuild(t *testing.T) {
	dir := t.TempDir()
	indexPath := filepath.Join(dir, "test.bleve")

	ix, err := NewIndexer(indexPath, 768)
	if err != nil {
		t.Fatalf("NewIndexer: %v", err)
	}
	defer ix.Close()

	// Create docs directory with files
	docsDir := filepath.Join(dir, "docs")
	os.Mkdir(docsDir, 0755)
	os.WriteFile(filepath.Join(docsDir, "one.md"), []byte("## Section A\n\nContent A."), 0644)
	os.WriteFile(filepath.Join(docsDir, "two.md"), []byte("## Section B\n\nContent B."), 0644)

	emb := embedder.NewMockEmbedder(768)
	secCfg := config.SecurityConfig{
		ExtensionAllowlist: []string{".md", ".txt"},
		DirectoryBlocklist: []string{".git"},
		MaxFileSizeBytes:   1 * 1024 * 1024,
	}

	result, err := AtomicRebuild(
		context.Background(),
		ix, emb, secCfg, 16000,
		docsDir, "global", "reference",
	)
	if err != nil {
		t.Fatalf("AtomicRebuild: %v", err)
	}

	if result.Indexed != 2 {
		t.Errorf("Indexed = %d, want 2", result.Indexed)
	}
	if result.Chunks != 2 {
		t.Errorf("Chunks = %d, want 2", result.Chunks)
	}
}
